public Elements siblingElements() {
    Element parent = parent();
    if (parent == null) return new Elements();
    List<Element> siblings = parent.children();
    Elements els = new Elements();
    for (Element el : siblings) {
        if (el != this) els.add(el);
    }
    return els;
}

public Element nextElementSibling() {
    Element parent = parent();
    if (parent == null) return null;
    List<Element> siblings = parent.children();
    Integer index = indexInList(this, siblings);
    if (index != null && siblings.size() > index + 1)
        return siblings.get(index + 1);
    return null;
}

public Element previousElementSibling() {
    Element parent = parent();
    if (parent == null) return null;
    List<Element> siblings = parent.children();
    Integer index = indexInList(this, siblings);
    if (index != null && index > 0)
        return siblings.get(index - 1);
    return null;
}

public List<Node> siblingNodes() {
    if (parentNode == null) return new ArrayList<Node>(0);
    List<Node> nodes = parentNode.childNodes();
    List<Node> out = new ArrayList<Node>(Math.max(0, nodes.size() - 1));
    for (Node n : nodes) {
        if (n != this) out.add(n);
    }
    return out;
}

